// No Toll Road mod — completely disables tolls

// Patch the toll check so it never triggers
if (typeof checkAndShowToll === 'function') {
  const origCheckToll = checkAndShowToll;
  window.checkAndShowToll = function(afterCallback) {
    // Never show toll
    if (afterCallback) afterCallback();
    return false;
  };
}

// Also neutralize payToll and skipToll just in case
if (typeof payToll === 'function') {
  window.payToll = function() {
    const overlay = document.getElementById('toll-overlay');
    if (overlay) overlay.classList.add('hidden');
    document.getElementById('toll-shop-section').style.display = 'none';
    if (window._tollCallback) window._tollCallback();
  };
}

if (typeof skipToll === 'function') {
  window.skipToll = function() {
    const overlay = document.getElementById('toll-overlay');
    if (overlay) overlay.classList.add('hidden');
    if (window._tollCallback) window._tollCallback();
  };
}

// Hide toll overlay if somehow shown
setTimeout(() => {
  const tollOverlay = document.getElementById('toll-overlay');
  if (tollOverlay) tollOverlay.classList.add('hidden');
}, 500);

// Optional: give a one-time credit bonus for freedom
credits += 50;
updateHUD();

return {
  unload: function() {
    // Restore original if needed (though not strictly necessary)
    if (origCheckToll) window.checkAndShowToll = origCheckToll;
  }
};
